members.step_text:
1. 打开本特性的License配置开关。
  SET LICENSESWITCH
2. 查询接口名。
  LST INTERFACE :;
3. 配置VPN实例。
  ADD L3VPNINST ;
  ADD VPNINSTAF ;
4. 配置VNRS_VNFC外联口物理IP。
    a. 配置主接口的管理状态为up。
      MOD INTERFACE ;
    b. 配置以太网子接口。
      ADD INTERFACE ;
    c. 增加接口绑定VPN。
      ADD IPBINDVPN ;
    d. 在以太网子接口上关联VLAN ID。
      ADD ETHSUBIF ;
      > 说明
      > - 子接口配置了VLAN，则需要在交换机、对接网关上调整VLAN的配置。
      > - 双平面组网场景下，要求双平面的两个trunk允许通过的Vlan不同，避免环路风险。
    e. 使能IPv6接口。
      SET IFIPV6ENABLE ;
    f. 配置外联口的物理IP。
      ADD IFIPV6ADDRESS ;

1. 检查IPAPM是否已安装，若未安装，请完成IPAPM安装，参见 安装IPAPM服务 。
  预期结果：“未就绪进程数”和“故障进程数”均为0。

  DSP CELLSTAT: OBJECT=PODTYPE, PODTYPE="ipapmctrl-pod";
  DSP CELLSTAT: OBJECT=PODTYPE, PODTYPE="ipapmexec-pod";
2. 打开本特性的Licence开关。
  SET LICENSESWITCH

1. 检查IPAPM是否已安装，若未安装，请完成IPAPM安装，参见 安装IPAPM服务 。
  预期结果：“未就绪进程数”和“故障进程数”均为0。

  DSP CELLSTAT: OBJECT=PODTYPE, PODTYPE="ipapmctrl-pod";
  DSP CELLSTAT: OBJECT=PODTYPE, PODTYPE="ipapmexec-pod";
2. 打开本特性的Licence开关。
  SET LICENSESWITCH

1. 增加APN实例。
  ADD APN :APN=APN名称;
2. 将带宽控制方式绑定到APN用例下。
  SET APNQOSATTR :APN=APN名称,CARSHAPEUL=上行CARSHAPE开关,CARSHAPEDL=下行CARSHAPE开关;

1. 增加VPN组
  在 “MML命令行-UDG” 窗口上执行：
  ADD SQOSVPNGROUP : VPNGROUPNAME="VPN组名称";
2. 增加VPN组成员
  在 “MML命令行-UDG” 窗口上执行：
  ADD SQOSVPNGROUPMEM : VPNGROUPNAME="VPN组名称", VPNNAME="VPN名称", VPNPRIORITY="VPN优先级";

- 删除已经创建的VPN组
  在 “MML命令行-UDG” 窗口上执行：
  RMV SQOSVPNGROUP :VPNGROUPNAME="VPN组名称";
- 删除VPN组成员
  在 “MML命令行-UDG” 窗口上执行：
  RMV SQOSVPNGROUPMEM : VPNGROUPNAME="VPN组名称", VPNNAME="VPN名称";

1. 删除对应的DSCPMAP。
  在 “MML命令行-UDG” 窗口上执行：
  RMV DSCPMAP : DSCP=DSCP值,TYPE=优先级类型,VALUE=优先级数值;

1. 配置DSCP到VLAN优先级的映射。
  在 “MML命令行-UDG” 窗口上执行：
  ADD_DSCPMAP : DSCP=DSCP值,TYPE=优先级类型,VALUE=优先级数值;

1. 删除ACL6规则。
  在 “MML命令行-UDG” 窗口上执行：
  RMV ACLRULEADV6 : ACLNAME="IPv6 ACL规则组标识", ACLRULENAME="规则名称";
2. 删除ACL6规则组。
  在 “MML命令行-UDG” 窗口上执行：
  RMV ACLGROUP6 : ACLNAME="IPv6 ACL规则组标识";

- 删除GRE隧道。
  在 “MML命令行-UDG” 窗口上执行：
  RMV GRETUNNEL :TNLNAME="隧道名称", TNLTYPE=隧道类型;

5. 添加IPv6路径MTU配置。
  ADD IPV6PATHMTU ;
6. 可选：配置静态路由。
  ADD SRROUTE6 ;
  > 说明
  > 如果需要为静态路由绑定静态BFD会话，通过 ADD SRROUTE6 的“静态BFD会话名”来指定静态路由所联动的静态BFD的会话名。

1. 删除接口出方向绑定流策略。
  在 “MML命令行-UDG” 窗口上执行：
  RMV QOSAPPLICATION : IFNAME="接口 名称 ",DIRECTION= 报文方向 ;
2. 删除绑定的流分类和流行为。
  在 “MML命令行-UDG” 窗口上执行：
  RMV MQCPOLICYNODE : POLICYNAME="策略名称",CLASSIFIERNAME="分类名称" ,BEHAVIORNAME="行为名称" ;
3. 删除流策略。
  在 “MML命令行-UDG” 窗口上执行：
  RMV MQCPOLICY : POLICYNAME="策略名称";
5. 删除流分类。
  在 “MML命令行-UDG” 窗口上执行：
  RMV MQCCLASSIFIER : CLASSIFIERNAME="分类名称";
6. 可选：删除流动作。
    - （可选）删除重定向下一跳动作：
      在 “MML命令行-UDG” 窗口上执行：
      RMV QOSACTRDRNHP :BEHAVIORNAME="行为名称";
    - （可选）删除重标记：
      在 “MML命令行-UDG” 窗口上执行：
      RMV SQOSREMARK :BEHAVIORNAME="流行为名称";
    - （可选）删除级联流策略：
      在 “MML命令行-UDG” 窗口上执行：
      RMV QOSACTRDRPOLICY : BEHAVIORNAME="行为名称";
    - （可选）删除重定向VPN组：
      在 “MML命令行-UDG” 窗口上执行：
      RMV SQOSRDRVPNGROUP : BEHAVIORNAME="行为名称";
    - （可选）删除安全URPF：
      在 “MML命令行-UDG” 窗口上执行：
      RMV SQOSURPF : BEHAVIORNAME="流行为名称";
    - （可选）删除CAR配置：
      在 “MML命令行-UDG” 窗口上执行：
      RMV SQOSCAR : BEHAVIORNAME="流行为名称";
7. 删除流行为。
  在 “MML命令行-UDG” 窗口上执行：
  RMV MQCBEHAVIOR : BEHAVIORNAME="行为名称";

2. 增加流行为。
  在 “MML命令行-UDG” 窗口上执行：
  ADD MQCBEHAVIOR :BEHAVIORNAME="行为名称";
3. 增加对应的流动作。
  在 “MML命令行-UDG” 窗口上执行：
    - （可选）配置重定向下一跳动作：
      ADD QOSACTRDRNHP :BEHAVIORNAME=" 流 行为名称", IPVERSION=IPv4, NEXTHOP="下一跳 地址 ";
    - （可选）配置重标记：
      ADD SQOSREMARK :BEHAVIORNAME="流行为名称", V4DSCPVALUE="IPv4的DSCP值", V6DSCPVALUE="IPv6的DSCP值", DFVALUE="DF值";
    - （可选）配置deny动作：
      SET QOSACTFILTER :BEHAVIORNAME="行为名称", FILTER=deny;
    - （可选）配置级联流策略动作：
      ADD QOSACTRDRPOLICY :BEHAVIORNAME="行为名称", POLICYNAME="策略名称";
    - （可选）配置重定向VPN组：
      ADD SQOSRDRVPNGROUP :VPNGROUPNAME="VPN组名称", BEHAVIORNAME="行为名称";
      需要先使用 ADD SQOSVPNGROUP 命令添加VPN组，使用 ADD L3VPNINST 命令添加VPN实例，使用 ADD SQOSVPNGROUPMEM 命令向VPN组添加VPN成员。
    - （可选）配置安全URPF：
      ADD SQOSURPF :BEHAVIORNAME="流行为名称", URPFTYPE="URPF检查类型", URPFDEFAULT="匹配默认路由";
    - （可选）配置CAR：
      ADD SQOSCAR :BEHAVIORNAME="流行为名称", CIR="承诺信息速率";
  > 说明
  > 流动作permit可以和其他动作共存，其他都是互斥的。
4. 增加流分类。
  在 “MML命令行-UDG” 窗口上执行：
  ADD MQCCLASSIFIER :CLASSIFIERNAME="分类名称";
5. 流分类绑定ACL规则。
  在 “MML命令行-UDG” 窗口上执行：
    - 绑定基于名称和编号的ACL规则：
      ADD QOSRULEACL :CLASSIFIERNAME="分类名称",IPVERSION=IPv4,ACLTYPE=acl-name,ACLNAME="ACL名称";

6. 增加流策略，并绑定流行为和流分类。
  在 “MML命令行-UDG” 窗口上执行：
    - 增加流策略：
      ADD MQCPOLICY :POLICYNAME="策略名称";
    - 绑定流分类和流行为：
      ADD MQCPOLICYNODE :POLICYNAME="策略名称",CLASSIFIERNAME="分类名称",BEHAVIORNAME="行为名称";
7. 将流策略应用到指定的接口视图。
  在 “MML命令行-UDG” 窗口上执行：
  ADD QOSAPPLICATION :POLICYNAME="策略名称",IFNAME="接口名称",DIRECTION= 报文 方向;
8. 使能流策略统计。
  在 “MML命令行-UDG” 窗口上执行：
  MOD MQCPOLICY :POLICYNAME="策略名称",STCENABLE=统计使能标志;

1. 删除对应的QOSIFTRUST。
  在 “MML命令行-UDG” 窗口上执行：
  RMV QOSIFTRUST : IFNAME="接口名 称 ";
2. 删除对应的DiffServ域。
  在 “MML命令行-UDG” 窗口上执行：
  RMV QOSDIFFERSERV : DSNAME=" DS名称 ";
3. （可选）删除对应的重定向至指定VPN的配置。
  在 “MML命令行-UDG” 窗口上执行：
  RMV QOSRDRVPN : IFNAME ="接口名称";
4. （可选）去激活QoS不检查PHB表。
  在 “MML命令行-UDG” 窗口上执行：
  RMV QOSIFPHB : IFNAME="接口名 称 ", PHBTYPE= 出接口报文的优先级字段映射类型 ;

1. 删除接口ACL规则。
  在 “MML命令行-UDG” 窗口上执行：
  RMV ACLRULEIF : ACLNAME="ACL规则组标识", ACLRULENAME="规则名称";
2. 删除以太ACL规则。
  在 “MML命令行-UDG” 窗口上执行：
  RMV ACLRULEETH : ACLNAME="ACL规则组标识", ACLRULENAME="规则名称";
3. 删除高级ACL规则。
  在 “MML命令行-UDG” 窗口上执行：
  RMV ACLRULEADV4 : ACLNAME="ACL规则组标识", ACLRULENAME="规则名称";
4. 删除基本ACL规则。
  在 “MML命令行-UDG” 窗口上执行：
  RMV ACLRULEBAS4 : ACLNAME="ACL规则组标识", ACLRULENAME="规则名称";
5. 删除ACL规则组。
  在 “MML命令行-UDG” 窗口上执行：
  RMV ACLGROUP : ACLNAME="ACL规则组标识";
